SELECT site_name, location, elevation
FROM sites
WHERE location = (SELECT location FROM sites WHERE site_name = 'Site A');

SELECT access_date, user_id
FROM data_access
WHERE access_type = 'download' AND user_id = 1;

SELECT DISTINCT data_access.user_id, sites.site_name
FROM data_access
INNER JOIN sites ON data_access.record_id = sites.site_id;

SELECT access_date, access_type, ip_address, user_agent 
FROM data_access 
WHERE access_id = 1;

SELECT COUNT(*)
FROM data_access
WHERE user_id = 0;

SELECT 
  (SELECT user_id FROM users WHERE role = 'data analyst') AS User_ID,
  (SELECT location FROM sites WHERE last_maintenance_date > '2022-12-31') AS Location;
